example_bad:
-- УЯЗВИМО: конкатенация пользовательского ввода
-- user_input может содержать: ' OR '1'='1
SELECT * FROM sys_employee WHERE name = '' || user_input || '';

-- УЯЗВИМО: UNION для кражи данных из других таблиц
SELECT id, name FROM sys_employee WHERE id = 1
UNION SELECT inn, attr_email FROM sys_company;

-- УЯЗВИМО: удаляет ВСЕ записи!
DELETE FROM scp_application;

-- УЯЗВИМО: обновляет ВСЕ строки!
UPDATE sys_employee SET status = 0;

example_good:
-- БЕЗОПАСНО: удалить конкретное заявление
DELETE FROM scp_application WHERE id = $1 AND status = 1;

-- БЕЗОПАСНО: обновить конкретного сотрудника
UPDATE sys_employee SET status = 0 WHERE id = $1;

example_bad:
-- УЯЗВИМО: возвращает sensitive поля email, phone, inn
SELECT * FROM sys_employee;
SELECT * FROM sys_company WHERE status = 1;

example_good:
-- БЕЗОПАСНО: только нужные поля
SELECT id, name, sur_name, first_name, org_id FROM sys_employee WHERE status = 1;
SELECT id, name, short_name, business_segment FROM sys_company WHERE status = 1;

example_bad:
-- УЯЗВИМО: может вернуть миллионы строк транзакций
SELECT * FROM afhd_ac_trans_link WHERE account_date > '2024-01-01';

-- УЯЗВИМО: без пагинации
SELECT id, name FROM sys_employee ORDER BY id;

example_good:
-- БЕЗОПАСНО: белый список таблиц + %I для идентификаторов
CREATE OR REPLACE FUNCTION get_data(tbl text)
RETURNS SETOF record SECURITY DEFINER AS $$
BEGIN
  IF tbl NOT IN ('sys_employee', 'sys_company') THEN
    RAISE EXCEPTION 'Invalid table: %', tbl;
  END IF;
  EXECUTE format('SELECT id, name FROM %I', tbl);
END;
$$ LANGUAGE plpgsql;

example_bad:
-- УЯЗВИМО: %s не экранирует значение
CREATE OR REPLACE FUNCTION search_emp(search_name text)
RETURNS SETOF sys_employee AS $$
DECLARE
  sql text;
BEGIN
  sql := format('SELECT * FROM sys_employee WHERE name = ''%s''', search_name);
  EXECUTE sql;  -- ОПАСНО!
END;
$$ LANGUAGE plpgsql;

example_good:
-- БЕЗОПАСНО: USING для параметров или прямой запрос
CREATE OR REPLACE FUNCTION search_emp(search_name text)
RETURNS SETOF sys_employee AS $$
BEGIN
  RETURN QUERY
  SELECT id, name, sur_name FROM sys_employee WHERE name = search_name;
  -- Или с динамическим SQL:
  -- EXECUTE 'SELECT id, name FROM sys_employee WHERE name = $1' USING search_name;
END;
$$ LANGUAGE plpgsql;
